function PropertyGrid({ properties, onAddProperty }) {
  const { div, h1, span } = tags;
  const [view, setView] = createSignal('cards');
  const [search, setSearch] = createSignal('');
  const [statusFilter, setStatusFilter] = createSignal('all');

  const filtered = () => properties.filter(p => {
    if (statusFilter() !== 'all' && p.status !== statusFilter()) return false;
    if (search() && !p.address.toLowerCase().includes(search().toLowerCase())) return false;
    return true;
  });

  const totalUnits = properties.reduce((sum, p) => sum + p.units, 0);
  const avgOccupancy = Math.round(properties.reduce((sum, p) => sum + p.occupancyRate, 0) / properties.length);
  const totalRevenue = properties.reduce((sum, p) => sum + p.monthlyRevenue, 0);

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('_flex _jcsb _aic') },
      h1({ class: css('_heading3') }, 'Properties'),
      div({ class: css('_flex _gap2') },
        div({ class: css('_flex _r1 _border _overflow[hidden]') },
          Button({ variant: view() === 'cards' ? 'default' : 'ghost', size: 'sm', onclick: () => setView('cards') }, icon('grid')),
          Button({ variant: view() === 'table' ? 'default' : 'ghost', size: 'sm', onclick: () => setView('table') }, icon('list')),
          Button({ variant: view() === 'map' ? 'default' : 'ghost', size: 'sm', onclick: () => setView('map') }, icon('map'))
        ),
        Button({ variant: 'primary', onclick: onAddProperty }, icon('plus'), 'Add Property')
      )
    ),
    div({ class: css('_grid _cols4 _gap4') },
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block') }, properties.length),
        span({ class: css('_textsm _fgmuted') }, 'Total Properties')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block') }, totalUnits),
        span({ class: css('_textsm _fgmuted') }, 'Total Units')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block _fgsuccess') }, `${avgOccupancy}%`),
        span({ class: css('_textsm _fgmuted') }, 'Avg Occupancy')
      ),
      div({ class: css('estate-card-metric _p4') },
        span({ class: css('_heading2 _block') }, `$${totalRevenue.toLocaleString()}`),
        span({ class: css('_textsm _fgmuted') }, 'Monthly Revenue')
      )
    ),
    div({ class: css('_flex _gap4 _aic') },
      Input({ type: 'search', placeholder: 'Search properties...', value: search(), oninput: e => setSearch(e.target.value), class: css('_w64') }),
      Select({ value: statusFilter(), onchange: e => setStatusFilter(e.target.value) },
        tags.option({ value: 'all' }, 'All Status'),
        tags.option({ value: 'active' }, 'Active'),
        tags.option({ value: 'inactive' }, 'Inactive')
      )
    ),
    div({ class: css('_grid _cols3 _gap4') },
      ...filtered().map(property => PropertyCard({ property }))
    )
  );
}

