function PropertyTable({ properties }) {
  const { div, table, thead, tbody, tr, th, td } = tags;

  return div({ class: css('estate-table _overflow[auto]') },
    table({ class: css('_wfull _textleft') },
      thead({},
        tr({ class: css('_bgSurface') },
          th({ class: css('_p3 _font500') }, 'Property'),
          th({ class: css('_p3 _font500') }, 'Type'),
          th({ class: css('_p3 _font500 _tc') }, 'Units'),
          th({ class: css('_p3 _font500 _tc') }, 'Occupancy'),
          th({ class: css('_p3 _font500 _tr') }, 'Revenue'),
          th({ class: css('_p3 _font500 _tc') }, 'Status'),
          th({ class: css('_p3') })
        )
      ),
      tbody({},
        ...properties.map((p, i) =>
          tr({ class: css(i % 2 === 0 ? '' : '_bgSurfaceRaised') },
            td({ class: css('_p3') },
              div({ class: css('_font500') }, p.name || p.address),
              div({ class: css('_textsm _fgmuted') }, `${p.city}, ${p.state}`)
            ),
            td({ class: css('_p3') }, Badge({ variant: 'outline' }, p.type)),
            td({ class: css('_p3 _tc') }, p.units),
            td({ class: css('_p3 _tc') }, `${p.occupancyRate}%`),
            td({ class: css('_p3 _tr _font500') }, `$${p.monthlyRevenue.toLocaleString()}`),
            td({ class: css('_p3 _tc') }, Badge({ variant: p.status === 'active' ? 'success' : 'default' }, p.status)),
            td({ class: css('_p3') }, Button({ variant: 'ghost', size: 'sm' }, icon('chevron-right')))
          )
        )
      )
    )
  );
}

function PropertyMap({ properties, onSelectProperty }) {
  const { div, span } = tags;

  return div({ class: css('_flex _hfull') },
    div({ class: css('_w80 _overflow[auto] _borderR') },
      ...properties.map(p => PropertyCardCompact({ property: p, onclick: () => onSelectProperty(p) }))
    ),
    div({ class: css('_flex1 _bgSurfaceRaised _flex _aic _jcc') },
      span({ class: css('_fgmuted') }, 'Map integration placeholder - connect to mapping service')
    )
  );
}

